// Synthesize crypto market regime from all fetched data

const funding = $('Fetch Funding').first().json;
const oi = $('Fetch Open Interest').first().json;
const liquidations = $('Fetch Liquidations').first().json;
const globalData = $('Fetch Global Data').first().json;
const prices = $('Fetch Prices').first().json;

const fundingBtc = funding?.btc ?? 0;
const fundingEth = funding?.eth ?? 0;
const oiBtcChange = oi?.btc?.change_1h ?? 0;
const oiEthChange = oi?.eth?.change_1h ?? 0;
const longLiq = liquidations?.longs_4h ?? 0;
const shortLiq = liquidations?.shorts_4h ?? 0;
const btcDom = globalData?.btc_dominance ?? 0;
const ethDom = globalData?.eth_dominance ?? 0;

const avgFunding = (fundingBtc + fundingEth) / 2;
const avgOiChange = (oiBtcChange + oiEthChange) / 2;

const keySignals = [];
let regime = 'NEUTRAL';
let confidence = 'baja';
let narrative = '';

// Regime logic
if (avgFunding > 0.05 && avgOiChange > 3 && oiBtcChange > 0) {
  regime = 'BULLISH_MOMENTUM';
  confidence = avgFunding > 0.10 ? 'alta' : 'media';
  keySignals.push(`Funding BTC ${fundingBtc.toFixed(2)}%`, `OI BTC +${oiBtcChange.toFixed(1)}%`);
  narrative = `Funding positivo elevado en BTC/ETH sugiere momentum bullish. OI subiendo confirma entrada de capital. `;
} else if (avgFunding > 0.05 && avgOiChange < 0) {
  regime = 'OVERHEATED_CORRECTION';
  confidence = 'media';
  keySignals.push(`Funding ETH ${fundingEth.toFixed(2)}%`, `OI ETH ${oiEthChange.toFixed(1)}%`);
  narrative = `Funding positivo alto con OI decreciendo indica mercado sobrecalentado. Probable corrección inminente. `;
} else if (longLiq > shortLiq * 1.5 && avgFunding < 0) {
  regime = 'PANIC';
  confidence = 'alta';
  keySignals.push(`Longs liq ${longLiq}M`, `Funding negativo ${avgFunding.toFixed(2)}%`);
  narrative = `Liquidaciones de longs masivas con funding negativo indica pánico. Posible capitulación. `;
} else if (avgFunding < -0.03 && avgOiChange > 2) {
  regime = 'SHORT_SQUEEZE_POTENTIAL';
  confidence = 'media';
  keySignals.push(`Funding negativo ${avgFunding.toFixed(2)}%`, `OI subiendo`);
  narrative = `Funding negativo con OI subiendo sugiere potencial short squeeze. `;
} else if (avgFunding < 0 && avgOiChange < 0) {
  regime = 'ACCUMULATION';
  confidence = 'media';
  narrative = `Funding negativo y OI decreciendo sugiere acumulación en rango. `;
} else {
  regime = 'NEUTRAL';
  confidence = 'baja';
  narrative = `Mercado en equilibrio. Sin señal clara de dirección. `;
}

// Enrich with prices
if (prices?.BTC) keySignals.push(`BTC $${prices.BTC.toLocaleString()}`);
if (prices?.ETH) keySignals.push(`ETH $${prices.ETH.toLocaleString()}`);

return {
  regime,
  confidence,
  key_signals: keySignals,
  narrative: narrative + `BTC Dom: ${btcDom.toFixed(1)}% | ETH Dom: ${ethDom.toFixed(1)}%.`,
  raw: { funding, oi, liquidations, globalData, prices }
};

// Format complete crypto market snapshot

const synth = $input.first().json;
const funding = synth.raw?.funding ?? {};
const oi = synth.raw?.oi ?? {};
const liquidations = synth.raw?.liquidations ?? {};
const globalData = synth.raw?.globalData ?? {};
const prices = synth.raw?.prices ?? {};

const now = new Date();
const fecha = now.toISOString().split('T')[0];
const hora = now.toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Madrid' });

// Format funding rates table
const fundingLines = ['=== FUNDING RATES ==='];
if (funding.byAsset) {
  for (const [asset, data] of Object.entries(funding.byAsset)) {
    const bins = data.binance ? `Binance ${data.binance.toFixed(2)}%` : '';
    const bybt = data.bybit ? `Bybit ${data.bybit.toFixed(2)}%` : '';
    const okx = data.okx ? `OKX ${data.okx.toFixed(2)}%` : '';
    const hl = data.huobi ? `HL ${data.huobi.toFixed(2)}%` : '';
    fundingLines.push(`${asset}: ${[bins, bybt, okx, hl].filter(Boolean).join(' | ')}`);
  }
} else {
  fundingLines.push(`BTC: Binance ${(funding.btc?.binance ?? 0).toFixed(2)}% | Bybit ${(funding.btc?.bybit ?? 0).toFixed(2)}% | OKX ${(funding.btc?.okx ?? 0).toFixed(2)}%`);
  fundingLines.push(`ETH: Binance ${(funding.eth?.binance ?? 0).toFixed(2)}% | Bybit ${(funding.eth?.bybit ?? 0).toFixed(2)}% | OKX ${(funding.eth?.okx ?? 0).toFixed(2)}%`);
}

// Format OI section
const oiLines = ['=== OPEN INTEREST & LIQUIDACIONES ==='];
if (oi.btc) oiLines.push(`BTC OI: $${(oi.btc.usd / 1e9).toFixed(1)}B (${oi.btc.change_1h >= 0 ? '+' : ''}${oi.btc.change_1h.toFixed(1)}% 1h)`);
if (oi.eth) {
  const ethWarning = oi.eth.change_1h > 10 ? ' ⚠️' : '';
  oiLines.push(`ETH OI: $${(oi.eth.usd / 1e9).toFixed(1)}B (${oi.eth.change_1h >= 0 ? '+' : ''}${oi.eth.change_1h.toFixed(1)}% 1h)${ethWarning}`);
}

// Liquidations
if (liquidations.longs_4h || liquidations.shorts_4h) {
  oiLines.push(`Longs liq 4h: $${liquidations.longs_4h}M | Shorts: $${liquidations.shorts_4h}M`);
}

// Dominance
const domLines = ['=== DOMINANCE & GLOBAL ==='];
domLines.push(`BTC Dom: ${(globalData.btc_dominance ?? 0).toFixed(1)}% | ETH Dom: ${(globalData.eth_dominance ?? 0).toFixed(1)}%`);
domLines.push(`Régimen global: ${synth.regime}`);

const fullSnapshot = `CRYPTO MARKET SNAPSHOT — ${fecha} ${hora}
RÉGIMEN ACTUAL: ${synth.regime} (confianza: ${synth.confidence})
${synth.narrative}
${fundingLines.join('\n')}
${oiLines.join('\n')}
${domLines.join('\n')}`;

const jsonOutput = {
  regime: synth.regime,
  confidence: synth.confidence,
  key_signals: synth.key_signals,
  narrative: synth.narrative,
  timestamp: now.toISOString(),
  funding_rates: funding,
  open_interest: oi,
  liquidations: liquidations,
  dominance: {
    btc: globalData.btc_dominance,
    eth: globalData.eth_dominance
  },
  prices: prices,
  full_text: fullSnapshot
};

return [jsonOutput];
